// Add at the start of your canary handler:
const defaultLaunchOptions = await synthetics.getDefaultLaunchOptions();
const newLaunchArgs = defaultLaunchOptions.args.filter(
  launchArg => launchArg !== '--single-process'
);
await synthetics.launch({ args: newLaunchArgs });

// Disable all step screenshots:
syntheticsConfiguration.disableStepScreenshots();

// Or selectively via setConfig:
syntheticsConfiguration.setConfig({
  screenshotOnStepStart: false,
  screenshotOnStepSuccess: false,
  screenshotOnStepFailure: false,
});
